+				inString = true;
+			}
+			continue;
+		}
+
+		if (escaped) {
+			output += character;
+			escaped = false;
+			continue;
+		}
+
+		if (character === "\\") {
+			output += character;
+			escaped = true;
+			continue;
+		}
+
+		if (character === '"') {
+			output += character;
+			inString = false;
+			continue;
