+		if (character === "\r") {
+			output += "\\r";
+			continue;
+		}
+		if (character === "\t") {
+			output += "\\t";
+			continue;
+		}
+		if (character.charCodeAt(0) < 0x20) {
+			output += `\\u${character.charCodeAt(0).toString(16).padStart(4, "0")}`;
+			continue;
+		}
+
+		output += character;
+	}
+
+	return output;
